const prev = $('Parse HR Request').first().json;
const res = $input.first().json;
const status = res.statusCode ?? res.status;
if (status === 404) {
  return [{ json: { ...prev, exists: false, already_exists: false } }];
}
if (status >= 200 && status < 300) {
  const content = res.body?.content ?? res.content;
  const parsed = JSON.parse(Buffer.from(content, 'base64').toString('utf8'));
  return [{
    json: {
      ok: true,
      already_exists: true,
      exists: true,
      agent_id: parsed.agent_id,
      path: prev.path,
      npub: parsed.nostr?.npub,
      display_name: parsed.nostr?.display_name,
      httpStatus: 200,
    },
  }];
}
return [{ json: { ok: false, error: 'github_get_failed', httpStatus: 502 } }];

