function validateHelgaIdentity(obj) {
  const details = [];
  if (!obj || typeof obj !== 'object') return { ok: false, error: 'invalid_identity', details: ['body'] };
  for (const key of ['role_title', 'department', 'system_prompt']) {
    if (typeof obj[key] !== 'string' || !obj[key].trim()) details.push(key);
  }
  if (!Array.isArray(obj.required_tools)) details.push('required_tools');
  if (!Array.isArray(obj.guardrails)) details.push('guardrails');
  if (details.length) return { ok: false, error: 'invalid_identity', details };
  return {
    ok: true,
    value: {
      role_title: obj.role_title.trim(),
      department: obj.department.trim(),
      system_prompt: obj.system_prompt,
      required_tools: obj.required_tools,
      guardrails: obj.guardrails,
    },
  };
}
const prev = $('Parse HR Request').first().json;
const res = $input.first().json;
const status = res.statusCode ?? res.status;
if (!status || status < 200 || status >= 300) {
  return [{ json: { ok: false, error: 'helga_unavailable', httpStatus: 502 } }];
}
let raw = res.body ?? res;
if (typeof raw === 'string') {
  try { raw = JSON.parse(raw); } catch { return [{ json: { ok: false, error: 'helga_unavailable', httpStatus: 502 } }]; }
}
let candidate = raw;
if (typeof raw.text === 'string') {
  const t = raw.text.trim();
  try { candidate = JSON.parse(t); } catch {
    const m = t.match(/```(?:json)?\s*([\s\S]*?)```/);
    if (m) { try { candidate = JSON.parse(m[1]); } catch { /* keep */ } }
    else { try { candidate = JSON.parse(t); } catch { return [{ json: { ok: false, error: 'helga_unavailable', httpStatus: 502 } }]; }
  }
} else if (raw.json && typeof raw.json === 'object') {
  candidate = raw.json;
}
const v = validateHelgaIdentity(candidate);
if (!v.ok) {
  return [{ json: { ok: false, error: v.error, details: v.details, httpStatus: 422 } }];
}
return [{ json: { ok: true, helga: v.value, agent_id: prev.agent_id, path: prev.path, payload: prev.payload, githubRepo: prev.githubRepo, relay: prev.relay } }];

try {
  const { faker } = require('@faker-js/faker/locale/de');
  const item = $input.first().json;
  const first = faker.person.firstName();
  const display_name = `${first} (${item.helga.role_title})`;
  return [{ json: { ...item, display_name, first_name: first } }];
} catch (e) {
  return [{ json: { ok: false, error: 'faker_unavailable', httpStatus: 500, details: String(e) } }];
}

const item = $input.first().json;
try {
  const nostr = require('nostr-tools');
  const generateSecretKey = nostr.generateSecretKey || nostr.pure?.generateSecretKey;
  const getPublicKey = nostr.getPublicKey || nostr.pure?.getPublicKey;
  const finalizeEvent = nostr.finalizeEvent || nostr.pure?.finalizeEvent;
  const nip19 = nostr.nip19;
  const sk = generateSecretKey();
  const pk = getPublicKey(sk);
  const nsec = nip19.nsecEncode(sk);
  const npub = nip19.npubEncode(pk);
  const display_name = item.display_name;
  const about = `${item.helga.department} · ${item.helga.role_title}`;
  const event = finalizeEvent({
    kind: 0,
    created_at: Math.floor(Date.now() / 1000),
    tags: [],
    content: JSON.stringify({ name: display_name, about }),
  }, sk);
  const relay = item.relay || 'wss://nostr.neberg.de';
  const ok = await new Promise((resolve, reject) => {
    const ws = new WebSocket(relay);
    const t = setTimeout(() => { try { ws.close(); } catch (_) {} reject(new Error('nostr publish timeout')); }, 10000);
    ws.addEventListener('open', () => { ws.send(JSON.stringify(['EVENT', event])); });
    ws.addEventListener('message', (msg) => {
      try {
        const data = JSON.parse(typeof msg.data === 'string' ? msg.data : msg.data.toString());
        if (data[0] === 'OK' && data[1] === event.id) {
          clearTimeout(t);
          try { ws.close(); } catch (_) {}
          resolve(data[2] === true);
        }
      } catch (e) { /* ignore non-json */ }
    });
    ws.addEventListener('error', () => { clearTimeout(t); reject(new Error('nostr ws error')); });
  });
  if (!ok) {
    return [{ json: { ok: false, error: 'nostr_profile_failed', httpStatus: 502 } }];
  }
  return [{ json: { ...item, npub, nsec, ok: true } }];
} catch (e) {
  return [{ json: { ok: false, error: 'nostr_profile_failed', httpStatus: 502, details: String(e) } }];
}

const RELAY_DEFAULT = 'wss://nostr.neberg.de';
function buildPublicIdentity({ helga, agentId, npub, displayName, relay }) {
  return {
    agent_id: agentId,
    role_title: helga.role_title,
    department: helga.department,
    system_prompt: helga.system_prompt,
    required_tools: helga.required_tools,
    guardrails: helga.guardrails,
    nostr: {
      npub,
      display_name: displayName,
      relay: relay || RELAY_DEFAULT,
    },
  };
}
const item = $input.first().json;
const staticData = $getWorkflowStaticData('global');
staticData.employeeNsecs = staticData.employeeNsecs || {};
staticData.employeeNsecs[item.agent_id] = item.nsec;
const identity = buildPublicIdentity({
  helga: item.helga,
  agentId: item.agent_id,
  npub: item.npub,
  displayName: item.display_name,
  relay: item.relay,
});
const fileContent = JSON.stringify(identity, null, 2);
const contentBase64 = Buffer.from(fileContent, 'utf8').toString('base64');
return [{
  json: {
    ok: true,
    agent_id: item.agent_id,
    path: item.path,
    githubRepo: item.githubRepo,
    npub: item.npub,
    display_name: item.display_name,
    contentBase64,
    nsec_stored: true,
  },
}];

const prev = $('Store nsec Build JSON').first().json;
const res = $input.first().json;
const status = res.statusCode ?? res.status;
if (!status || status < 200 || status >= 300) {
  return [{
    json: {
      ok: false,
      error: 'github_commit_failed',
      httpStatus: 502,
      npub: prev.npub,
      orphan_nostr_key: true,
    },
  }];
}
const body = res.body ?? res;
const commitSha = body.commit?.sha || body.content?.sha || null;
return [{
  json: {
    ok: true,
    already_exists: false,
    agent_id: prev.agent_id,
    path: prev.path,
    commit_sha: commitSha,
    npub: prev.npub,
    display_name: prev.display_name,
    httpStatus: 200,
  },
}];
